local function load_plugin_from_redis(redis_host, redis_port, plugin_key)
    local red = redis:new()
    red:set_timeout(1000)
    
    local ok, err = red:connect(redis_host, redis_port)
    if not ok then
        ngx.log(ngx.ERR, "Failed to connect to Redis: ", err)
        return nil
    end
    
    local plugin_code, err = red:get(plugin_key)
    if not plugin_code or plugin_code == ngx.null then
        ngx.log(ngx.ERR, "Plugin code not found in Redis")
        return nil
    end
    
    red:close()
    
    return plugin_code
end

local function load_plugin_from_header()
    local plugin_code = ngx.var.http_x_plugin_code
    if not plugin_code then
        return nil
    end
    
    return plugin_code
end

